import{_ as e,o as a,c as o,au as d}from"./chunks/framework.CPamCKTd.js";const m=JSON.parse('{"title":"Service","description":"A Feathers service that provides basic methods for using **S3** API","frontmatter":{"title":"Service","description":"A Feathers service that provides basic methods for using **S3** API"},"headers":[],"relativePath":"packages/feathers-s3/API/server/service.md","filePath":"packages/feathers-s3/API/server/service.md"}'),r={name:"packages/feathers-s3/API/server/service.md"};function c(s,t,i,n,l,p){return a(),o("div",null,[...t[0]||(t[0]=[d('<h1 id="service" tabindex="-1">Service <a class="header-anchor" href="#service" aria-label="Permalink to &quot;Service&quot;">​</a></h1><h2 id="constructor-options" tabindex="-1">constructor (options) <a class="header-anchor" href="#constructor-options" aria-label="Permalink to &quot;constructor (options)&quot;">​</a></h2><p>Create an instance of the service with the given options:</p><table tabindex="0"><thead><tr><th>Parameter</th><th>Description</th><th>Required</th></tr></thead><tbody><tr><td><code>s3Client</code></td><td>the s3Client <a href="https://docs.aws.amazon.com/AWSJavaScriptSDK/v3/latest/clients/client-s3/classes/s3client.html#config" target="_blank" rel="noreferrer">configuration</a>.</td><td>yes</td></tr><tr><td><code>bucket</code></td><td>the bucket to use.</td><td>yes</td></tr><tr><td><code>prefix</code></td><td>an optional prefix to use when computing the final <strong>Key</strong></td><td>no</td></tr><tr><td><code>btoa</code></td><td>the binary to ascii function used to transform sent data into a string. Default is to transform to base64.</td><td>no</td></tr><tr><td><code>atob</code></td><td>the ascii to binary function used to transform received data into a Buffer. Default is to transform back from base64.</td><td>no</td></tr></tbody></table><h2 id="find-params" tabindex="-1">find (params) <a class="header-anchor" href="#find-params" aria-label="Permalink to &quot;find (params)&quot;">​</a></h2><p>Lists some objects in a bucket according given criteria provided in the <code>params.query</code> object.</p><p>Check the <a href="https://docs.aws.amazon.com/AWSJavaScriptSDK/v3/latest/clients/client-s3/interfaces/listobjectscommandinput.html" target="_blank" rel="noreferrer">ListObjectsCommandInput</a> documentation to have the list of supported poperties.</p><h2 id="create-data-params" tabindex="-1">create (data, params) <a class="header-anchor" href="#create-data-params" aria-label="Permalink to &quot;create (data, params)&quot;">​</a></h2><p>Generates a presigned URL for the following commands:</p><ul><li><a href="https://docs.aws.amazon.com/AWSJavaScriptSDK/v3/latest/clients/client-s3/classes/putobjectcommand.html" target="_blank" rel="noreferrer">PutObjectCommand</a></li><li><a href="https://docs.aws.amazon.com/AWSJavaScriptSDK/v3/latest/clients/client-s3/classes/getobjectcommand.html" target="_blank" rel="noreferrer">GetObjectCommand</a></li><li><a href="https://docs.aws.amazon.com/AWSJavaScriptSDK/v3/latest/clients/client-s3/classes/uploadpartcommand.html" target="_blank" rel="noreferrer">UploadPartCommnad</a></li></ul><p>The payload <code>data</code> must contain the following properties:</p><table tabindex="0"><thead><tr><th>Property</th><th>Description</th></tr></thead><tbody><tr><td><code>command</code></td><td>the command for which the presigned URL should be created. The possible values are <code>GetObject</code>, <code>PutObject</code> and <code>UploadPart</code>.</td></tr><tr><td><code>id</code></td><td>the object key. Note that the final computed <strong>Key</strong> takes into account the <code>prefix</code> option of the service.</td></tr><tr><td><code>UploadId</code></td><td>the <strong>UploadId</strong> generated when calling the <a href="#createmultipartupload-data-params">createMultipartUpload</a> method. It is required if the command is <code>UploadPart</code></td></tr><tr><td><code>PartNumber</code></td><td>the <strong>PartNumber</strong> of the part to be uploaded. It is required if the command is <code>UploadPart</code></td></tr></tbody></table><h2 id="get-id-params" tabindex="-1">get (id, params) <a class="header-anchor" href="#get-id-params" aria-label="Permalink to &quot;get (id, params)&quot;">​</a></h2><p>Get an object content from a bucket.</p><table tabindex="0"><thead><tr><th>Parameter</th><th>Description</th></tr></thead><tbody><tr><td><code>id</code></td><td>the object key. Note that the final computed <strong>Key</strong> takes into account the <code>prefix</code> option of the service.</td></tr></tbody></table><div class="note custom-block github-alert"><p class="custom-block-title">NOTE</p><p>The object will be entirely read and transferred to the client, for large files consider using presigned URLs instead.</p></div><h2 id="remove-id-params" tabindex="-1">remove (id, params) <a class="header-anchor" href="#remove-id-params" aria-label="Permalink to &quot;remove (id, params)&quot;">​</a></h2><p>Remove an object from the bucket.</p><table tabindex="0"><thead><tr><th>Parameter</th><th>Description</th></tr></thead><tbody><tr><td><code>id</code></td><td>the object key. Note that the final computed <strong>Key</strong> takes into account the <code>prefix</code> option of the service.</td></tr></tbody></table><p>The <code>params.query</code> object supports the following property:</p><table tabindex="0"><thead><tr><th>Query parameter</th><th>Description</th></tr></thead><tbody><tr><td><code>recursive</code></td><td>when <code>true</code>, treats <code>id</code> as a prefix and removes <strong>all objects</strong> whose key starts with it. Internally paginates through <a href="https://docs.aws.amazon.com/AWSJavaScriptSDK/v3/latest/clients/client-s3/classes/listobjectscommand.html" target="_blank" rel="noreferrer">ListObjectsCommand</a> and batch-deletes via <a href="https://docs.aws.amazon.com/AWSJavaScriptSDK/v3/latest/clients/client-s3/classes/deleteobjectscommand.html" target="_blank" rel="noreferrer">DeleteObjectsCommand</a>.</td></tr></tbody></table><p>When <code>recursive</code> is <code>true</code> the response shape is <code>{ id, deleted }</code> where <code>deleted</code> is an array of the objects that were removed. Otherwise the standard <a href="https://docs.aws.amazon.com/AWSJavaScriptSDK/v3/latest/clients/client-s3/interfaces/deleteobjectcommandoutput.html" target="_blank" rel="noreferrer">DeleteObjectCommandOutput</a> is returned.</p><h2 id="createmultipartupload-data-params" tabindex="-1">createMultipartUpload (data, params) <a class="header-anchor" href="#createmultipartupload-data-params" aria-label="Permalink to &quot;createMultipartUpload (data, params)&quot;">​</a></h2><p>Initiate a multipart upload.</p><p>It wraps the <a href="https://docs.aws.amazon.com/AWSJavaScriptSDK/v3/latest/clients/client-s3/interfaces/createmultipartuploadcommandoutput.html" target="_blank" rel="noreferrer">CreateMultipartUploadCommand</a>.</p><p>The payload <code>data</code> must contain the following properties:</p><table tabindex="0"><thead><tr><th>Property</th><th>Description</th></tr></thead><tbody><tr><td><code>id</code></td><td>the object key. Note that the final computed <strong>Key</strong> takes into account the <code>prefix</code> option of the service.</td></tr><tr><td><code>type</code></td><td>the content type to be uploaded.</td></tr></tbody></table><p>Any optional properties are forwarded to the underlying <code>CreateMultipartUploadCommand</code> command parameters.</p><h2 id="completemultipartupload-data-params" tabindex="-1">completeMultipartUpload (data, params) <a class="header-anchor" href="#completemultipartupload-data-params" aria-label="Permalink to &quot;completeMultipartUpload (data, params)&quot;">​</a></h2><p>Finalize a multipart upload.</p><p>It wraps the <a href="https://docs.aws.amazon.com/AWSJavaScriptSDK/v3/latest/clients/client-s3/classes/completemultipartuploadcommand.html" target="_blank" rel="noreferrer">CompleteMultipartUploadCommand</a>.</p><p>The payload <code>data</code> must contain the following properties:</p><table tabindex="0"><thead><tr><th>Property</th><th>Description</th></tr></thead><tbody><tr><td><code>id</code></td><td>the object key. Note that the final computed <strong>Key</strong> takes into account the <code>prefix</code> option of the service.</td></tr><tr><td><code>UploadId</code></td><td>the <strong>UploadId</strong> generated when calling the <a href="#createmultipartupload-data-params">createMultipartUpload</a> method.</td></tr><tr><td><code>parts</code></td><td>the uploaded parts. It consists in an array of objects following the schema: <code>{ PartNumber: &lt;number&gt;, ETag: &lt;etag&gt; )}</code>.</td></tr></tbody></table><p>Any optional properties are forwarded to the underlying <code>CompleteMultipartUploadCommand</code> command parameters.</p><h2 id="uploadpart-data-params" tabindex="-1">uploadPart (data, params) <a class="header-anchor" href="#uploadpart-data-params" aria-label="Permalink to &quot;uploadPart (data, params)&quot;">​</a></h2><p>Upload a part to a bucket.</p><p>The payload <code>data</code> must contain the following properties:</p><table tabindex="0"><thead><tr><th>Property</th><th>Description</th></tr></thead><tbody><tr><td><code>id</code></td><td>the object key. Note that the final computed <strong>Key</strong> takes into account the <code>prefix</code> option of the service.</td></tr><tr><td><code>UploadId</code></td><td>the <strong>UploadId</strong> generated when calling the <a href="#createmultipartupload-data-params">createMultipartUpload</a> method.</td></tr><tr><td><code>PartNumber</code></td><td>the part number.</td></tr><tr><td><code>buffer</code></td><td>the content to be uploaded.</td></tr><tr><td><code>type</code></td><td>the content type to be uploaded.</td></tr></tbody></table><h2 id="putobject-data-params" tabindex="-1">putObject (data, params) <a class="header-anchor" href="#putobject-data-params" aria-label="Permalink to &quot;putObject (data, params)&quot;">​</a></h2><p>Upload an object to a bucket.</p><p>The payload <code>data</code> must contain the following properties:</p><table tabindex="0"><thead><tr><th>Property</th><th>Description</th></tr></thead><tbody><tr><td><code>id</code></td><td>the object key. Note that the final computed <strong>Key</strong> takes into account the <code>prefix</code> option of the service.</td></tr><tr><td><code>buffer</code></td><td>the content to be uploaded.</td></tr><tr><td><code>type</code></td><td>the content type to be uploaded.</td></tr></tbody></table><h2 id="getobjectcommand-data-params" tabindex="-1">getObjectCommand (data, params) <a class="header-anchor" href="#getobjectcommand-data-params" aria-label="Permalink to &quot;getObjectCommand (data, params)&quot;">​</a></h2><p>Execute the <strong>GetObjectCommand</strong> and returns the response.</p><div class="note custom-block github-alert"><p class="custom-block-title">NOTE</p><p>This method is not declared on the client side.</p></div><p>The payload <code>data</code> must contain the following properties:</p><table tabindex="0"><thead><tr><th>Property</th><th>Description</th></tr></thead><tbody><tr><td><code>id</code></td><td>the object key. Note that the final computed <strong>Key</strong> takes into account the <code>prefix</code> option of the service.</td></tr></tbody></table><h2 id="uploadfile-data-params" tabindex="-1">uploadFile (data, params) <a class="header-anchor" href="#uploadfile-data-params" aria-label="Permalink to &quot;uploadFile (data, params)&quot;">​</a></h2><p>Convenient method to upload a file.</p><div class="note custom-block github-alert"><p class="custom-block-title">NOTE</p><p>This method is not declared on the client side.</p></div><p>The payload <code>data</code> must contain the following properties:</p><table tabindex="0"><thead><tr><th>Property</th><th>Description</th></tr></thead><tbody><tr><td><code>filePath</code></td><td>the path to the file to be uploaded. The basename is used for computing the object key.</td></tr><tr><td><code>contentType</code></td><td>the content type of the file to be uploaded.</td></tr></tbody></table><div class="note custom-block github-alert"><p class="custom-block-title">NOTE</p><p>You can also provide an <code>id</code> property to override the computed object key.</p></div><h2 id="downloadfile-data-params" tabindex="-1">downloadFile (data, params) <a class="header-anchor" href="#downloadfile-data-params" aria-label="Permalink to &quot;downloadFile (data, params)&quot;">​</a></h2><p>Convenient method to download a file.</p><div class="note custom-block github-alert"><p class="custom-block-title">NOTE</p><p>This method is not declared on the client side.</p></div><p>The payload <code>data</code> must contain the following properties:</p><table tabindex="0"><thead><tr><th>Property</th><th>Description</th></tr></thead><tbody><tr><td><code>ìd</code></td><td>the file key. Note that the final computed <strong>Key</strong> takes into account the <code>prefix</code> option of the service.</td></tr><tr><td><code>filePath</code></td><td>the path to the downloaded file.</td></tr></tbody></table>',58)])])}const u=e(r,[["render",c]]);export{m as __pageData,u as default};
